import type { PlanDoc, Decision, DecisionAnalysis, ScopeItem } from '../types.ts';

// ── Helpers ──────────────────────────────────────────────────────────

function composeDetails(context?: string, rationale?: string): string | undefined {
  if (context && rationale) {
    return `${context}\n\nRecommendation rationale: ${rationale}`;
  }
  if (context) return context;
  if (rationale) return `Recommendation rationale: ${rationale}`;
  return undefined;
}

const CONFIDENCE_TAGS: Record<string, string> = {
  low: 'low-confidence',
  medium: 'medium-confidence',
  high: 'high-confidence',
};

const STAKES_TAGS: Record<string, string> = {
  low: 'low-stakes',
  high: 'high-stakes',
};

const CATEGORY_TAGS: Record<string, string> = {
  product: 'product',
  api: 'api',
  implementation: 'implementation',
};

const OBSERVABLE_TAGS: Record<string, string> = {
  true: 'observable',
  false: 'internal',
};

function buildAnalysisTags(analysis: DecisionAnalysis | undefined): string[] | undefined {
  if (!analysis) return undefined;

  const tags: string[] = [];

  if (analysis.confidence !== undefined && CONFIDENCE_TAGS[analysis.confidence]) {
    tags.push(CONFIDENCE_TAGS[analysis.confidence]);
  }
  if (analysis.stakes !== undefined && STAKES_TAGS[analysis.stakes]) {
    tags.push(STAKES_TAGS[analysis.stakes]);
  }
  if (analysis.category !== undefined && CATEGORY_TAGS[analysis.category]) {
    tags.push(CATEGORY_TAGS[analysis.category]);
  }
  if (analysis.observable !== undefined && OBSERVABLE_TAGS[String(analysis.observable)]) {
    tags.push(OBSERVABLE_TAGS[String(analysis.observable)]);
  }

  if (tags.length === 0) return undefined;
  return tags.sort();
}

function buildDecisionSummary(decisions: Decision[], scope: ScopeItem[]): string {
  const parts: string[] = [];

  if (decisions.length > 0) {
    parts.push('## Decisions');
    parts.push('');
    for (const decision of decisions) {
      parts.push(`### ${decision.id}: ${decision.question}`);
      if (decision.patronOverride) {
        parts.push(`**Patron override:** ${decision.patronOverride}`);
      } else if (decision.selected) {
        const label = decision.options[decision.selected] ?? decision.selected;
        parts.push(`**Selected:** ${label}`);
      }
      parts.push('');
    }
  }

  if (scope.length > 0) {
    parts.push('## Scope');
    parts.push('');
    for (const item of scope) {
      const check = item.included ? '[x]' : '[ ]';
      const suffix = item.included ? '' : ' (excluded)';
      parts.push(`- ${check} ${item.id}: ${item.description}${suffix}`);
    }
  }

  return parts.join('\n').trim();
}

// ── Engine factory ───────────────────────────────────────────────────

export function createDecisionReviewEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
  return {
    id: 'astrolabe.decision-review',

